<!DOCTYPE html>
<html lang="en">

<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>FrankenPHP | Welcome!</title>
  <meta name="robots" content="noindex">
  <style>
    html,
    body {
      margin: 0;
      padding: 0
    }

    * {
      box-sizing: border-box
    }

    a {
      color: #b7d84a;
      text-decoration: none
    }

    a:hover {
      color: #c9e86a
    }

    @keyframes floaty {

      0%,
      100% {
        transform: translateY(0) rotate(0)
      }

      50% {
        transform: translateY(-14px) rotate(-1.2deg)
      }
    }

    .wrap {
      height: 100dvh;
      background: #230143;
      display: flex;
      flex-direction: column;
      align-items: center;
      padding: clamp(20px, 3.5vh, 40px) clamp(20px, 4vw, 48px);
      font-family: system-ui, -apple-system, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
      overflow: hidden;
      position: relative
    }

    .dots {
      position: absolute;
      inset: 0;
      background-image: radial-gradient(rgba(183, 216, 74, .06) 1.2px, transparent 1.2px);
      background-size: 30px 30px;
      pointer-events: none;
      opacity: .6
    }

    .logo {
      width: clamp(180px, 22vw, 260px);
      height: auto;
      flex: none;
      align-self: flex-start;
      position: relative;
      z-index: 3;
      filter: drop-shadow(0 6px 20px rgba(0, 0, 0, .35))
    }

    .main {
      flex: 1 1 auto;
      min-height: 0;
      width: 100%;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      gap: clamp(14px, 2.4vh, 28px);
      position: relative;
      z-index: 2
    }

    .stage {
      min-height: 0;
      display: flex;
      justify-content: center;
      align-items: center
    }

    .art {
      width: auto;
      height: auto;
      max-width: min(480px, 82vw);
      max-height: 55vh;
      position: relative;
      z-index: 2;
      animation: floaty 5.5s ease-in-out infinite
    }

    .lede {
      flex: none;
      color: #c7bce6;
      font-size: clamp(16px, 1.6vw, 20px);
      font-weight: 400;
      text-align: center;
      max-width: 440px;
      line-height: 1.55;
      margin: 0;
    }

    .cta {
      flex: none;
      position: relative;
      display: inline-block;
      color: #390075;
      font-family: system-ui, -apple-system, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
      font-weight: 700;
      font-size: 20px;
      line-height: 1.4;
      padding: 10px 20px;
      text-decoration: none;
      transition: color .3s
    }

    .cta::before {
      content: "";
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 100%;
      height: 100%;
      background: #b3d133;
      z-index: 0;
      pointer-events: none;
      transition: all .3s
    }

    .cta::after {
      content: "";
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%) scale(1.5);
      width: 100%;
      height: 100%;
      border: 2px solid transparent;
      z-index: 0;
      pointer-events: none;
      transition: all .3s
    }

    .cta:hover {
      color: #b3d133
    }

    .cta:hover::before {
      transform: translate(-50%, -50%) scale(.5);
      background: transparent
    }

    .cta:hover::after {
      transform: translate(-50%, -50%) scale(1);
      border-color: #b3d133
    }

    .cta span {
      position: relative;
      z-index: 1
    }

    .foot {
      flex: none;
      margin-top: clamp(14px, 2.4vh, 26px);
      font-size: 13.5px;
      color: #8a7db3;
      letter-spacing: .2px;
      position: relative;
      z-index: 2
    }

    .foot a {
      color: #c7bce6;
      font-weight: 600;
      border-bottom: 1.5px solid rgba(183, 216, 74, .45);
      padding-bottom: 1px
    }
  </style>
</head>

